import{c as t,Q as a,j as n,m as s}from"./chunks/framework.rlpw0eGz.js";const u=JSON.parse('{"title":"Updating OpenIPC settings with the QuadroFleet firmware","description":"Step-by-step QuadroFleet update","frontmatter":{"title":"Updating OpenIPC settings with the QuadroFleet firmware","description":"Step-by-step QuadroFleet update","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/software/update-settings"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/software/update-settings"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/software/update-settings"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/software/update-settings"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/software/update-settings"}],["meta",{"property":"og:title","content":"Updating OpenIPC settings with the QuadroFleet firmware"}],["meta",{"property":"og:description","content":"Step-by-step QuadroFleet update"}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-software.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-software.png"}],["meta",{"name":"twitter:title","content":"Updating OpenIPC settings with the QuadroFleet firmware"}],["meta",{"name":"twitter:description","content":"Step-by-step QuadroFleet update"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Software\\",\\"item\\":\\"https://openfpv.com.ua/en/software/apfpv\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Updating OpenIPC settings with the QuadroFleet firmware\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Updating OpenIPC settings with the QuadroFleet firmware\\",\\"description\\":\\"Step-by-step QuadroFleet update\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/software/update-settings\\",\\"image\\":\\"https://openfpv.com.ua/og-software.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/software/update-settings.md","filePath":"en/software/update-settings.md","lastUpdated":1780228136000}'),i={name:"en/software/update-settings.md"};function p(o,e,r,l,c,d){return a(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="updating-openipc-settings-with-the-quadrofleet-firmware" tabindex="-1">Updating OpenIPC settings with the QuadroFleet firmware <a class="header-anchor" href="#updating-openipc-settings-with-the-quadrofleet-firmware" aria-label="Permalink to &quot;Updating OpenIPC settings with the QuadroFleet firmware&quot;">​</a></h1><p>This guide covers configuring the OpenIPC camera and the Masina client app for optimal QuadroFleet operation.</p><p>Prerequisites</p><ul><li>An OpenIPC camera with the QuadroFleet firmware.</li><li>A running WireGuard VPN server (see VPN Setup).</li><li>The QuadroFleet control app installed on a PC or smartphone.</li></ul><h3 id="step-1-configuring-the-openipc-camera" tabindex="-1">Step 1: Configuring the OpenIPC camera <a class="header-anchor" href="#step-1-configuring-the-openipc-camera" aria-label="Permalink to &quot;Step 1: Configuring the OpenIPC camera&quot;">​</a></h3><ol><li>Access the camera&#39;s web interface via its IP address (<code>http://10.253.0.2/</code> if the VPN is configured).</li><li>Go to <strong>Extensions</strong> &gt; <strong>WireGuard</strong> and configure:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>host=10.253.0.3</span></span>
<span class="line"><span>LOCAL_TIMEOUT=300000</span></span>
<span class="line"><span>FAILSAFE_TIMEOUT=10000</span></span>
<span class="line"><span>STABILIZE_TIMEOUT=250</span></span>
<span class="line"><span>ELRS_SWITCH_PIN=0</span></span>
<span class="line"><span>CONTROL_PORT=2223</span></span>
<span class="line"><span>CAM_INFO_PORT=2224</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li><code>host</code>: IP address of the operator device (e.g. PC/phone) on the VPN.</li><li><code>LOCAL_TIMEOUT</code>: Time (ms) before switching to ELRS mode (optional, set to 0 if not used).</li><li><code>FAILSAFE_TIMEOUT</code>: Time (ms) before entering failsafe mode (e.g. RTH).</li><li><code>STABILIZE_TIMEOUT</code>: Time (ms) before entering hover mode on connection loss.</li><li><code>ELRS_SWITCH_PIN</code>: GPIO pin for the ELRS switch (0 if not used).</li><li><code>CONTROL_PORT</code>: <strong>remote and local</strong> UDP port for control commands.</li><li><code>CAM_INFO_PORT</code>: remote UDP port for camera telemetry.</li></ul><ol start="3"><li>Save and reboot the camera.</li></ol><h3 id="step-2-configuring-the-video-stream" tabindex="-1">Step 2: Configuring the video stream <a class="header-anchor" href="#step-2-configuring-the-video-stream" aria-label="Permalink to &quot;Step 2: Configuring the video stream&quot;">​</a></h3><ol><li>In the web interface, go to <strong>Majestic</strong> &gt; <strong>Settings</strong>.</li><li>Configure the <strong>Video0</strong> parameters:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Video codec: h265</span></span>
<span class="line"><span>Video resolution: 960x720</span></span>
<span class="line"><span>Video frame rate: 60</span></span>
<span class="line"><span>Video bitrate: 256 kbps</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><ol start="3"><li>Alternatively, use the runtime settings:</li></ol><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>FPS: 60</span></span>
<span class="line"><span>Bitrate: 256 kbps</span></span>
<span class="line"><span>Video resolution: 960x720 4:3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><ol start="4"><li>Apply the changes and check the video stream through the control app.</li><li>Restart Majestic.</li></ol><h3 id="step-3-launching-the-control-app" tabindex="-1">Step 3: Launching the control app <a class="header-anchor" href="#step-3-launching-the-control-app" aria-label="Permalink to &quot;Step 3: Launching the control app&quot;">​</a></h3><ol><li>Launch the QuadroFleet app on your PC or smartphone.</li><li>Make sure the VPN tunnel is active (see VPN Setup).</li><li>Verify that the app receives video and telemetry: <ul><li>Check the OSD for battery, GPS and speed data.</li><li>Confirm that the interactive map shows the drone&#39;s position.</li></ul></li></ol>`,17)])])}const m=t(i,[["render",p]]);export{u as __pageData,m as default};
